"use client";

/**
 * 編集カレンダー / コンテンツカレンダー — オンラインメディア編集部向け
 * cold-start evaluation build of @gunjo/ui@0.0.1-alpha.2.
 *
 * HEADLINE GAP (confirmed against the installed package source AND gunjo.jp/docs):
 * the library ships NO month-calendar-with-events / event-calendar / agenda
 * primitive. `Calendar` is a react-day-picker date PICKER; `ScheduleGrid` is a
 * fixed rows×cols matrix whose cells take one `content` node (no day-number /
 * today / multi-chip-per-day). So the month grid (./MonthGrid) is hand-rolled
 * from div + role="grid" + roving tabindex. Everything ELSE is real @gunjo/ui:
 * Statistic (月サマリ), Badge w/ icon (color-independent status pills), Select +
 * removable Badge (filters), Tabs (view switch), Sheet + DatePicker + Input +
 * Textarea + Select (add/reschedule), DataTable (締切トラッカー), Card / Button /
 * Separator / Icon / Banner / EmptyState scaffolding.
 */

import * as React from "react";
import type { ColumnDef } from "@gunjo/ui";
import {
  Card,
  CardContent,
  Statistic,
  Badge,
  Button,
  Select,
  Separator,
  Icon,
  Banner,
  Tabs,
  TabsList,
  TabsTrigger,
  TabsContent,
  DataTable,
} from "@gunjo/ui";
import {
  IconChevronLeft,
  IconChevronRight,
  IconPlus,
  IconCalendarMonth,
  IconList,
  IconClockExclamation,
  IconFilterOff,
  IconCircleDot,
  IconCalendarStats,
} from "@tabler/icons-react";

import {
  type Article,
  type ChannelId,
  CHANNELS,
  CHANNEL_BY_ID,
  STATUS_BY_ID,
  EDITORS,
  CURRENT_MONTH,
  TODAY_ISO,
  seedArticles,
  buildMonthMatrix,
  fromIso,
  isOverdue,
} from "./data";
import { MonthGrid } from "./MonthGrid";
import { AgendaList } from "./AgendaList";
import { ArticleSheet, type ArticleDraft } from "./ArticleSheet";

const MONTH_LABELS = [
  "1月", "2月", "3月", "4月", "5月", "6月",
  "7月", "8月", "9月", "10月", "11月", "12月",
];

export default function ContentCalendarPage() {
  const [articles, setArticles] = React.useState<Article[]>(seedArticles);
  const [view, setView] = React.useState<{ year: number; month: number }>({
    year: CURRENT_MONTH.year,
    month: CURRENT_MONTH.month,
  });

  // filters
  const [channelFilter, setChannelFilter] = React.useState<ChannelId | "all">(
    "all"
  );
  const [editorFilter, setEditorFilter] = React.useState<string>("all");

  // editor sheet state
  const [sheetOpen, setSheetOpen] = React.useState(false);
  const [editing, setEditing] = React.useState<Article | null>(null);
  const [presetDate, setPresetDate] = React.useState<string | undefined>();

  const filtered = React.useMemo(
    () =>
      articles.filter(
        (a) =>
          (channelFilter === "all" || a.channel === channelFilter) &&
          (editorFilter === "all" || a.editor === editorFilter)
      ),
    [articles, channelFilter, editorFilter]
  );

  // Articles whose publish OR due date sits in the visible month — for summary.
  const monthArticles = React.useMemo(() => {
    const prefix = `${view.year}-${String(view.month + 1).padStart(2, "0")}`;
    return filtered.filter(
      (a) => a.publishDate.startsWith(prefix) || a.dueDate.startsWith(prefix)
    );
  }, [filtered, view]);

  const summary = React.useMemo(() => {
    const prefix = `${view.year}-${String(view.month + 1).padStart(2, "0")}`;
    const publishing = monthArticles.filter((a) =>
      a.publishDate.startsWith(prefix)
    );
    const awaiting = monthArticles.filter((a) => a.status === "submitted");
    const overdue = monthArticles.filter((a) => isOverdue(a, TODAY_ISO));
    return {
      publishing: publishing.length,
      awaiting: awaiting.length,
      overdue: overdue.length,
    };
  }, [monthArticles, view]);

  const weeks = React.useMemo(
    () => buildMonthMatrix(view.year, view.month, TODAY_ISO),
    [view]
  );

  const goPrev = () =>
    setView((v) =>
      v.month === 0
        ? { year: v.year - 1, month: 11 }
        : { year: v.year, month: v.month - 1 }
    );
  const goNext = () =>
    setView((v) =>
      v.month === 11
        ? { year: v.year + 1, month: 0 }
        : { year: v.year, month: v.month + 1 }
    );
  const goToday = () =>
    setView({ year: CURRENT_MONTH.year, month: CURRENT_MONTH.month });

  const hasFilters = channelFilter !== "all" || editorFilter !== "all";
  const clearFilters = () => {
    setChannelFilter("all");
    setEditorFilter("all");
  };

  const openAdd = (date?: string) => {
    setEditing(null);
    setPresetDate(date);
    setSheetOpen(true);
  };
  const openEdit = (a: Article) => {
    setEditing(a);
    setPresetDate(undefined);
    setSheetOpen(true);
  };

  const handleSave = (draft: ArticleDraft) => {
    setArticles((prev) => {
      if (draft.id) {
        return prev.map((a) =>
          a.id === draft.id ? ({ ...a, ...draft } as Article) : a
        );
      }
      const id = `n${Date.now()}`;
      return [...prev, { ...draft, id } as Article];
    });
  };
  const handleDelete = (id: string) =>
    setArticles((prev) => prev.filter((a) => a.id !== id));

  /* ---- deadline tracker columns (DataTable) ---- */
  const deadlineRows = React.useMemo(
    () =>
      [...monthArticles].sort((a, b) =>
        a.dueDate < b.dueDate ? -1 : a.dueDate > b.dueDate ? 1 : 0
      ),
    [monthArticles]
  );

  const columns = React.useMemo<ColumnDef<Article>[]>(
    () => [
      {
        accessorKey: "title",
        header: "記事タイトル",
        cell: ({ row }) => {
          const a = row.original;
          const ch = CHANNEL_BY_ID[a.channel];
          return (
            <div className="flex flex-col gap-0.5">
              <span className="font-medium text-foreground">{a.title}</span>
              <span className="text-xs text-muted-foreground">
                {ch.label}・担当 {a.editor}
              </span>
            </div>
          );
        },
      },
      {
        accessorKey: "status",
        header: "ステータス",
        cell: ({ row }) => {
          const st = STATUS_BY_ID[row.original.status];
          return (
            <Badge variant={st.badge} icon={<IconCircleDot />} className="h-5">
              {st.code} {st.label}
            </Badge>
          );
        },
      },
      {
        accessorKey: "dueDate",
        header: "入稿締切",
        cell: ({ row }) => {
          const a = row.original;
          const d = fromIso(a.dueDate);
          const overdue = isOverdue(a, TODAY_ISO);
          return (
            <div className="flex items-center gap-2 tabular-nums">
              <span className={overdue ? "font-semibold text-destructive" : ""}>
                {d.getMonth() + 1}/{d.getDate()}
              </span>
              {overdue && (
                <Badge
                  variant="warning"
                  icon={<IconClockExclamation />}
                  className="h-5"
                >
                  超過
                </Badge>
              )}
            </div>
          );
        },
      },
      {
        accessorKey: "publishDate",
        header: "公開予定",
        cell: ({ row }) => {
          const d = fromIso(row.original.publishDate);
          return (
            <span className="tabular-nums">
              {d.getMonth() + 1}/{d.getDate()}
            </span>
          );
        },
      },
    ],
    []
  );

  return (
    <main className="mx-auto flex w-full max-w-7xl flex-col gap-5 px-4 py-6 sm:px-6">
      {/* header */}
      <header className="flex flex-col gap-3">
        <div className="flex flex-wrap items-end justify-between gap-3">
          <div className="flex flex-col gap-1">
            <p className="flex items-center gap-1.5 text-xs font-medium text-muted-foreground">
              <Icon icon={IconCalendarStats} size="sm" aria-hidden />
              オンラインメディア編集部
            </p>
            <h1 className="text-2xl font-bold tracking-tight text-foreground">
              編集カレンダー
            </h1>
          </div>
          <Button onClick={() => openAdd()}>
            <Icon icon={IconPlus} size="sm" className="mr-1" aria-hidden />
            記事を追加
          </Button>
        </div>

        {summary.overdue > 0 && (
          <Banner
            variant="warning"
            icon={<Icon icon={IconClockExclamation} size="sm" aria-hidden />}
          >
            入稿締切を過ぎた記事が {summary.overdue} 件あります。
          </Banner>
        )}
      </header>

      {/* month summary */}
      <section aria-label="当月サマリ" className="grid grid-cols-1 gap-3 sm:grid-cols-3">
        <Statistic
          label={`${MONTH_LABELS[view.month]}の公開予定`}
          value={`${summary.publishing} 本`}
          hint="今月カレンダーに載る記事"
        />
        <Statistic
          label="入稿待ち"
          value={`${summary.awaiting} 本`}
          hint="入稿待ちステータスの記事"
          trend={summary.awaiting > 0 ? "up" : "flat"}
          tone="neutral"
        />
        <Statistic
          label="締切超過"
          value={`${summary.overdue} 本`}
          hint="締切を過ぎ未入稿"
          trend={summary.overdue > 0 ? "up" : "flat"}
          tone={summary.overdue > 0 ? "negative" : "neutral"}
        />
      </section>

      {/* month nav + filters */}
      <Card>
        <CardContent className="flex flex-col gap-4 p-4">
          <div className="flex flex-wrap items-center justify-between gap-3">
            <div className="flex items-center gap-1.5">
              <Button
                variant="outline"
                size="icon"
                onClick={goPrev}
                aria-label="前の月へ"
              >
                <Icon icon={IconChevronLeft} size="sm" aria-hidden />
              </Button>
              <h2
                className="min-w-[8.5rem] text-center text-lg font-semibold tabular-nums"
                aria-live="polite"
              >
                {view.year}年 {MONTH_LABELS[view.month]}
              </h2>
              <Button
                variant="outline"
                size="icon"
                onClick={goNext}
                aria-label="次の月へ"
              >
                <Icon icon={IconChevronRight} size="sm" aria-hidden />
              </Button>
              <Button variant="ghost" size="sm" onClick={goToday}>
                今日
              </Button>
            </div>

            <div className="flex flex-wrap items-center gap-2">
              <Select
                aria-label="カテゴリで絞り込み"
                value={channelFilter}
                onChange={(e) =>
                  setChannelFilter(e.target.value as ChannelId | "all")
                }
                className="h-9 w-36"
              >
                <option value="all">全カテゴリ</option>
                {CHANNELS.map((c) => (
                  <option key={c.id} value={c.id}>
                    {c.label}
                  </option>
                ))}
              </Select>
              <Select
                aria-label="担当者で絞り込み"
                value={editorFilter}
                onChange={(e) => setEditorFilter(e.target.value)}
                className="h-9 w-36"
              >
                <option value="all">全担当者</option>
                {EDITORS.map((ed) => (
                  <option key={ed} value={ed}>
                    {ed}
                  </option>
                ))}
              </Select>
            </div>
          </div>

          {/* active filter chips */}
          {hasFilters && (
            <div className="flex flex-wrap items-center gap-2">
              <span className="text-xs text-muted-foreground">絞り込み中：</span>
              {channelFilter !== "all" && (
                <Badge
                  variant="info"
                  onRemove={() => setChannelFilter("all")}
                  removeLabel="カテゴリ絞り込みを解除"
                >
                  {CHANNEL_BY_ID[channelFilter].label}
                </Badge>
              )}
              {editorFilter !== "all" && (
                <Badge
                  variant="info"
                  onRemove={() => setEditorFilter("all")}
                  removeLabel="担当者絞り込みを解除"
                >
                  {editorFilter}
                </Badge>
              )}
              <Button variant="ghost" size="xs" onClick={clearFilters}>
                <Icon icon={IconFilterOff} size="sm" className="mr-1" aria-hidden />
                すべて解除
              </Button>
            </div>
          )}

          <Separator />

          {/* status legend (color-independent) */}
          <div className="flex flex-wrap items-center gap-x-3 gap-y-1.5">
            <span className="text-xs font-medium text-muted-foreground">
              ステータス凡例：
            </span>
            {Object.values(STATUS_BY_ID).map((s) => (
              <Badge
                key={s.id}
                variant={s.badge}
                icon={<IconCircleDot />}
                className="h-5"
              >
                {s.code} {s.label}
              </Badge>
            ))}
            <span className="ml-2 inline-flex items-center gap-1 text-xs text-muted-foreground">
              <Icon icon={IconClockExclamation} size="sm" aria-hidden />
              締切超過
            </span>
          </div>
        </CardContent>
      </Card>

      {/* views */}
      <Tabs defaultValue="calendar" className="border-0">
        <TabsList>
          <TabsTrigger value="calendar">
            <Icon icon={IconCalendarMonth} size="sm" className="mr-1.5" aria-hidden />
            カレンダー
          </TabsTrigger>
          <TabsTrigger value="agenda">
            <Icon icon={IconList} size="sm" className="mr-1.5" aria-hidden />
            アジェンダ
          </TabsTrigger>
          <TabsTrigger value="deadlines">
            <Icon icon={IconClockExclamation} size="sm" className="mr-1.5" aria-hidden />
            締切一覧
          </TabsTrigger>
        </TabsList>

        {/* CALENDAR: month grid on md+, agenda fallback on mobile */}
        <TabsContent value="calendar" className="px-0">
          <div className="hidden md:block">
            <MonthGrid
              weeks={weeks}
              articles={filtered}
              todayIso={TODAY_ISO}
              onSelectArticle={openEdit}
              onSelectDay={(iso) => openAdd(iso)}
            />
          </div>
          <div className="md:hidden">
            <p className="mb-3 rounded-md bg-muted/60 px-3 py-2 text-xs text-muted-foreground">
              モバイルではアジェンダ表示に切り替わります（月グリッドは md 以上）。
            </p>
            <AgendaList
              articles={monthArticles.filter((a) =>
                a.publishDate.startsWith(
                  `${view.year}-${String(view.month + 1).padStart(2, "0")}`
                )
              )}
              todayIso={TODAY_ISO}
              onSelectArticle={openEdit}
              onAdd={() => openAdd()}
            />
          </div>
        </TabsContent>

        {/* AGENDA */}
        <TabsContent value="agenda" className="px-0">
          <AgendaList
            articles={monthArticles.filter((a) =>
              a.publishDate.startsWith(
                `${view.year}-${String(view.month + 1).padStart(2, "0")}`
              )
            )}
            todayIso={TODAY_ISO}
            onSelectArticle={openEdit}
            onAdd={() => openAdd()}
          />
        </TabsContent>

        {/* DEADLINES */}
        <TabsContent value="deadlines" className="px-0">
          <Card>
            <CardContent className="p-4">
              <DataTable
                columns={columns}
                data={deadlineRows}
                filter={{ columnId: "title", placeholder: "タイトルで検索…" }}
                pageSize={10}
                onRowClick={openEdit}
                labels={{
                  filterPlaceholder: "タイトルで検索…",
                  noResults: "該当する記事がありません",
                  previous: "前へ",
                  next: "次へ",
                  rowsPerPage: "表示件数",
                }}
                renderCard={(a) => {
                  const st = STATUS_BY_ID[a.status];
                  const ch = CHANNEL_BY_ID[a.channel];
                  const overdue = isOverdue(a, TODAY_ISO);
                  return (
                    <div className="flex flex-col gap-1.5">
                      <span className="text-sm font-medium">{a.title}</span>
                      <span className="text-xs text-muted-foreground">
                        {ch.label}・担当 {a.editor}
                      </span>
                      <div className="flex flex-wrap items-center gap-1.5">
                        <Badge variant={st.badge} icon={<IconCircleDot />} className="h-5">
                          {st.code} {st.label}
                        </Badge>
                        <span className="text-xs tabular-nums text-muted-foreground">
                          締切 {fromIso(a.dueDate).getMonth() + 1}/
                          {fromIso(a.dueDate).getDate()}
                        </span>
                        {overdue && (
                          <Badge variant="warning" icon={<IconClockExclamation />} className="h-5">
                            超過
                          </Badge>
                        )}
                      </div>
                    </div>
                  );
                }}
              />
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>

      <ArticleSheet
        open={sheetOpen}
        onOpenChange={setSheetOpen}
        article={editing}
        presetDate={presetDate}
        todayIso={TODAY_ISO}
        onSave={handleSave}
        onDelete={handleDelete}
      />
    </main>
  );
}

"use client";

/**
 * アジェンダ表示 — date-grouped list. Doubles as the mobile fallback for the
 * month grid (the grid is hidden < md; this list is the primary mobile view)
 * and as a desktop "list" tab. Built from @gunjo/ui List / Badge / Icon.
 */

import * as React from "react";
import { Badge, Icon, EmptyState, Button } from "@gunjo/ui";
import {
  IconCalendarOff,
  IconCircleDot,
  IconClockExclamation,
  IconFlag,
} from "@tabler/icons-react";
import {
  type Article,
  CHANNEL_BY_ID,
  STATUS_BY_ID,
  WEEKDAY_LABELS,
  fromIso,
  isOverdue,
} from "./data";

interface AgendaListProps {
  articles: Article[];
  todayIso: string;
  onSelectArticle: (a: Article) => void;
  onAdd: () => void;
}

export function AgendaList({
  articles,
  todayIso,
  onSelectArticle,
  onAdd,
}: AgendaListProps) {
  const groups = React.useMemo(() => {
    const map = new Map<string, Article[]>();
    for (const a of [...articles].sort((x, y) =>
      x.publishDate < y.publishDate ? -1 : 1
    )) {
      const arr = map.get(a.publishDate) ?? [];
      arr.push(a);
      map.set(a.publishDate, arr);
    }
    return [...map.entries()];
  }, [articles]);

  if (groups.length === 0) {
    return (
      <EmptyState
        icon={<Icon icon={IconCalendarOff} size="lg" />}
        title="この条件の記事はありません"
        description="フィルターを変更するか、新しい記事を追加してください。"
        action={
          <Button size="sm" onClick={onAdd}>
            記事を追加
          </Button>
        }
      />
    );
  }

  return (
    <ol className="flex flex-col gap-4">
      {groups.map(([iso, items]) => {
        const d = fromIso(iso);
        const isToday = iso === todayIso;
        return (
          <li key={iso} className="flex flex-col gap-2">
            <div className="flex items-baseline gap-2">
              <h3 className="text-sm font-semibold text-foreground">
                {d.getMonth() + 1}月{d.getDate()}日
                <span className="ml-1 text-xs font-normal text-muted-foreground">
                  ({WEEKDAY_LABELS[d.getDay()]})
                </span>
              </h3>
              {isToday && (
                <Badge variant="info" className="h-4 px-1.5 text-[10px]">
                  今日
                </Badge>
              )}
            </div>
            <ul className="flex flex-col gap-1.5">
              {items.map((a) => {
                const st = STATUS_BY_ID[a.status];
                const ch = CHANNEL_BY_ID[a.channel];
                const overdue = isOverdue(a, todayIso);
                return (
                  <li key={a.id}>
                    <button
                      type="button"
                      onClick={() => onSelectArticle(a)}
                      className="flex w-full flex-col gap-1.5 rounded-lg border border-border bg-card p-3 text-left transition-colors hover:border-ring hover:bg-accent focus:outline-none focus-visible:ring-2 focus-visible:ring-ring"
                    >
                      <span className="flex items-start justify-between gap-2">
                        <span className="text-sm font-medium leading-snug text-foreground">
                          {a.title}
                        </span>
                        <span className="rounded-sm bg-muted px-1.5 py-0.5 text-[10px] font-bold text-muted-foreground">
                          {ch.code}
                        </span>
                      </span>
                      <span className="flex flex-wrap items-center gap-1.5">
                        <Badge
                          variant={st.badge}
                          icon={<IconCircleDot />}
                          className="h-5"
                        >
                          {st.code} {st.label}
                        </Badge>
                        <span className="inline-flex items-center gap-0.5 text-[11px] text-muted-foreground">
                          <Icon icon={IconFlag} size="sm" aria-hidden />
                          入稿締切 {fromIso(a.dueDate).getMonth() + 1}/
                          {fromIso(a.dueDate).getDate()}
                        </span>
                        {overdue && (
                          <Badge
                            variant="warning"
                            icon={<IconClockExclamation />}
                            className="h-5"
                          >
                            締切超過
                          </Badge>
                        )}
                        <span className="text-[11px] text-muted-foreground">
                          担当 {a.editor}
                        </span>
                      </span>
                    </button>
                  </li>
                );
              })}
            </ul>
          </li>
        );
      })}
    </ol>
  );
}

"use client";

/**
 * 予定の追加 / 編集 / 移動 — a side Sheet (@gunjo/ui Sheet) hosting a small form
 * built from Input / Textarea / Select / DatePicker. Handles both:
 *   - add a new article on a clicked day (predate=that day)
 *   - edit + reschedule (move publish/due dates via DatePicker) an existing one
 */

import * as React from "react";
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetDescription,
  SheetFooter,
  Input,
  Textarea,
  Select,
  DatePicker,
  Button,
  Separator,
  Badge,
  Icon,
} from "@gunjo/ui";
import { IconClockExclamation, IconTrash } from "@tabler/icons-react";
import {
  type Article,
  type ChannelId,
  type StatusId,
  type Editor,
  CHANNELS,
  STATUSES,
  EDITORS,
  STATUS_BY_ID,
  fromIso,
  toIso,
  isOverdue,
} from "./data";

export interface ArticleDraft {
  id?: string;
  title: string;
  channel: ChannelId;
  status: StatusId;
  editor: Editor;
  publishDate: string;
  dueDate: string;
}

interface ArticleSheetProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  /** Existing article to edit, or null to add. */
  article: Article | null;
  /** Prefill publish date when adding from a day click. */
  presetDate?: string;
  todayIso: string;
  onSave: (draft: ArticleDraft) => void;
  onDelete?: (id: string) => void;
}

const emptyDraft = (presetDate: string): ArticleDraft => ({
  title: "",
  channel: "news",
  status: "idea",
  editor: EDITORS[0],
  publishDate: presetDate,
  dueDate: presetDate,
});

export function ArticleSheet({
  open,
  onOpenChange,
  article,
  presetDate,
  todayIso,
  onSave,
  onDelete,
}: ArticleSheetProps) {
  const [draft, setDraft] = React.useState<ArticleDraft>(() =>
    emptyDraft(presetDate ?? todayIso)
  );
  const [titleError, setTitleError] = React.useState(false);

  // Reseed the form whenever the sheet opens for a different target.
  React.useEffect(() => {
    if (!open) return;
    setTitleError(false);
    if (article) {
      setDraft({ ...article });
    } else {
      setDraft(emptyDraft(presetDate ?? todayIso));
    }
  }, [open, article, presetDate, todayIso]);

  const isEdit = Boolean(article);
  const overdue =
    draft.id != null
      ? isOverdue(draft as Article, todayIso)
      : draft.dueDate < todayIso &&
        !["review", "scheduled", "published"].includes(draft.status);

  const submit = () => {
    if (!draft.title.trim()) {
      setTitleError(true);
      return;
    }
    onSave(draft);
    onOpenChange(false);
  };

  return (
    <Sheet open={open} onOpenChange={onOpenChange}>
      <SheetContent side="right" className="flex w-full flex-col gap-0 sm:max-w-md">
        <SheetHeader>
          <SheetTitle>{isEdit ? "記事を編集" : "記事を追加"}</SheetTitle>
          <SheetDescription>
            {isEdit
              ? "公開予定日・入稿締切を変更して予定を移動できます。"
              : "タイトルと公開予定日を入力してカレンダーに追加します。"}
          </SheetDescription>
        </SheetHeader>

        <div className="flex flex-1 flex-col gap-4 overflow-y-auto py-4">
          <Input
            label="記事タイトル"
            placeholder="例：生成AIで変わる編集現場の最前線"
            value={draft.title}
            aria-invalid={titleError || undefined}
            description={
              titleError ? "タイトルを入力してください。" : undefined
            }
            onChange={(e) => {
              setDraft((d) => ({ ...d, title: e.target.value }));
              if (e.target.value.trim()) setTitleError(false);
            }}
          />

          <div className="grid grid-cols-2 gap-3">
            <Select
              label="カテゴリ"
              value={draft.channel}
              onChange={(e) =>
                setDraft((d) => ({ ...d, channel: e.target.value as ChannelId }))
              }
            >
              {CHANNELS.map((c) => (
                <option key={c.id} value={c.id}>
                  {c.label}
                </option>
              ))}
            </Select>
            <Select
              label="ステータス"
              value={draft.status}
              onChange={(e) =>
                setDraft((d) => ({ ...d, status: e.target.value as StatusId }))
              }
            >
              {STATUSES.map((s) => (
                <option key={s.id} value={s.id}>
                  {s.label}
                </option>
              ))}
            </Select>
          </div>

          <Select
            label="担当者"
            value={draft.editor}
            onChange={(e) =>
              setDraft((d) => ({ ...d, editor: e.target.value as Editor }))
            }
          >
            {EDITORS.map((ed) => (
              <option key={ed} value={ed}>
                {ed}
              </option>
            ))}
          </Select>

          <Separator />

          <div className="flex flex-col gap-1.5">
            <label className="text-sm font-medium leading-none text-foreground">
              公開予定日
            </label>
            <DatePicker
              value={fromIso(draft.publishDate)}
              editable
              showTodayButton
              onValueChange={(date) =>
                date &&
                setDraft((d) => ({ ...d, publishDate: toIso(date) }))
              }
            />
          </div>

          <div className="flex flex-col gap-1.5">
            <label className="text-sm font-medium leading-none text-foreground">
              入稿締切
            </label>
            <DatePicker
              value={fromIso(draft.dueDate)}
              editable
              showTodayButton
              onValueChange={(date) =>
                date && setDraft((d) => ({ ...d, dueDate: toIso(date) }))
              }
            />
            {overdue && (
              <Badge
                variant="warning"
                icon={<IconClockExclamation />}
                className="mt-1 h-5 w-fit"
              >
                締切超過：入稿待ちのまま締切を過ぎています
              </Badge>
            )}
          </div>

          <div className="rounded-md border border-border bg-muted/40 p-3 text-xs text-muted-foreground">
            プレビュー：
            <span className="ml-1 font-semibold text-foreground">
              {draft.title || "（無題）"}
            </span>
            <span className="ml-1">
              — {STATUS_BY_ID[draft.status].label}
            </span>
          </div>
        </div>

        <SheetFooter className="flex-col-reverse gap-2 sm:flex-row sm:justify-between">
          {isEdit && onDelete && article ? (
            <Button
              variant="ghost"
              onClick={() => {
                onDelete(article.id);
                onOpenChange(false);
              }}
              className="text-destructive"
            >
              <Icon icon={IconTrash} size="sm" className="mr-1" aria-hidden />
              削除
            </Button>
          ) : (
            <span />
          )}
          <div className="flex gap-2">
            <Button variant="outline" onClick={() => onOpenChange(false)}>
              キャンセル
            </Button>
            <Button onClick={submit}>{isEdit ? "保存" : "追加"}</Button>
          </div>
        </SheetFooter>
      </SheetContent>
    </Sheet>
  );
}

