/* ---- date helpers (no external dep; calendar math is local) ---- */

export function toIso(d: Date): string {
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, "0");
  const day = String(d.getDate()).padStart(2, "0");
  return `${y}-${m}-${day}`;
}

export function fromIso(iso: string): Date {
  const [y, m, d] = iso.split("-").map(Number);
  return new Date(y, m - 1, d);
}

export const WEEKDAY_LABELS = ["日", "月", "火", "水", "木", "金", "土"] as const;

export interface DayCell {
  iso: string;
  date: Date;
  dayOfMonth: number;
  inMonth: boolean;
  isToday: boolean;
  weekday: number; // 0=Sun
}

/** Build a 6-row weeks × 7 day matrix covering the given month (Sun-first). */
export function buildMonthMatrix(
  year: number,
  month: number,
  todayIso: string
): DayCell[][] {
  const first = new Date(year, month, 1);
  const start = new Date(first);
  start.setDate(1 - first.getDay()); // back up to the Sunday on/before the 1st

  const weeks: DayCell[][] = [];
  const cursor = new Date(start);
  for (let w = 0; w < 6; w++) {
    const row: DayCell[] = [];
    for (let d = 0; d < 7; d++) {
      const iso = toIso(cursor);
      row.push({
        iso,
        date: new Date(cursor),
        dayOfMonth: cursor.getDate(),
        inMonth: cursor.getMonth() === month,
        isToday: iso === todayIso,
        weekday: cursor.getDay(),
      });
      cursor.setDate(cursor.getDate() + 1);
    }
    weeks.push(row);
  }
  return weeks;
}

/** 締切超過: due date has passed and the article is not yet 入稿済 (review/scheduled/published). */
export function isOverdue(a: Article, todayIso: string): boolean {
  const submittedStates: StatusId[] = ["review", "scheduled", "published"];
  return a.dueDate < todayIso && !submittedStates.includes(a.status);
}

"use client";

/**
 * 月間カレンダー (week × weekday day-cell grid) — HAND-ROLLED.
 *
 * Why hand-rolled: @gunjo/ui ships no month-calendar-with-events primitive.
 * `Calendar` is a react-day-picker date PICKER; `ScheduleGrid` is a fixed
 * rows×cols matrix whose cells take a single `content` node (no day-number /
 * today / multi-chip-per-day concept). So the grid skeleton + a11y is local,
 * but every leaf (event chip, status pill, deadline marker, "+N件" affordance)
 * is a real @gunjo/ui component (Badge / Button / Icon).
 *
 * a11y: role="grid" with rowgroup/row/gridcell, aria-selected on the focused
 * cell, roving tabindex + full arrow-key / Home / End / Enter navigation.
 */

import * as React from "react";
import { Badge, Button, Icon } from "@gunjo/ui";
import {
  IconCircleDot,
  IconClockExclamation,
  IconFlag,
} from "@tabler/icons-react";
import {
  type Article,
  type DayCell,
  CHANNEL_BY_ID,
  STATUS_BY_ID,
  WEEKDAY_LABELS,
  isOverdue,
} from "./data";

const STATUS_BADGE_ICON = IconCircleDot;

/** Articles publishing on a given ISO date. */
function publishOn(articles: Article[], iso: string) {
  return articles.filter((a) => a.publishDate === iso);
}
/** Articles whose 入稿締切 falls on a given ISO date. */
function dueOn(articles: Article[], iso: string) {
  return articles.filter((a) => a.dueDate === iso);
}

interface MonthGridProps {
  weeks: DayCell[][];
  articles: Article[];
  todayIso: string;
  onSelectArticle: (a: Article) => void;
  onSelectDay: (iso: string) => void;
}

const MAX_CHIPS = 3;

export function MonthGrid({
  weeks,
  articles,
  todayIso,
  onSelectArticle,
  onSelectDay,
}: MonthGridProps) {
  // roving focus position [row, col]
  const [active, setActive] = React.useState<[number, number]>([0, 0]);
  const cellRefs = React.useRef(new Map<string, HTMLDivElement | null>());

  const focusCell = (r: number, c: number) => {
    const nr = Math.max(0, Math.min(weeks.length - 1, r));
    const nc = Math.max(0, Math.min(6, c));
    setActive([nr, nc]);
    cellRefs.current.get(`${nr}-${nc}`)?.focus();
  };

  const onKeyDown = (e: React.KeyboardEvent<HTMLDivElement>) => {
    const [r, c] = active;
    switch (e.key) {
      case "ArrowRight":
        e.preventDefault();
        focusCell(c === 6 ? r + 1 : r, c === 6 ? 0 : c + 1);
        break;
      case "ArrowLeft":
        e.preventDefault();
        focusCell(c === 0 ? r - 1 : r, c === 0 ? 6 : c - 1);
        break;
      case "ArrowDown":
        e.preventDefault();
        focusCell(r + 1, c);
        break;
      case "ArrowUp":
        e.preventDefault();
        focusCell(r - 1, c);
        break;
      case "Home":
        e.preventDefault();
        focusCell(r, 0);
        break;
      case "End":
        e.preventDefault();
        focusCell(r, 6);
        break;
      case "Enter":
      case " ": {
        e.preventDefault();
        const cell = weeks[r]?.[c];
        if (cell) onSelectDay(cell.iso);
        break;
      }
    }
  };

  return (
    <div
      role="grid"
      aria-label="月間コンテンツカレンダー"
      aria-readonly="false"
      className="w-full overflow-hidden rounded-lg border border-border bg-card"
      onKeyDown={onKeyDown}
    >
      {/* weekday header */}
      <div role="row" className="grid grid-cols-7 border-b border-border bg-muted">
        {WEEKDAY_LABELS.map((w, i) => (
          <div
            key={w}
            role="columnheader"
            className={
              "px-2 py-2 text-center text-xs font-semibold " +
              (i === 0
                ? "text-destructive"
                : i === 6
                ? "text-info"
                : "text-muted-foreground")
            }
          >
            {w}
          </div>
        ))}
      </div>

      {/* weeks */}
      <div role="rowgroup">
        {weeks.map((week, r) => (
          <div
            key={r}
            role="row"
            className="grid grid-cols-7 border-b border-border last:border-b-0"
          >
            {week.map((cell, c) => {
              const pubs = publishOn(articles, cell.iso);
              const dues = dueOn(articles, cell.iso);
              const isActive = active[0] === r && active[1] === c;
              const overflow = pubs.length - MAX_CHIPS;

              return (
                <div
                  key={cell.iso}
                  role="gridcell"
                  aria-selected={isActive}
                  aria-label={cellAriaLabel(cell, pubs, dues, todayIso)}
                  tabIndex={isActive ? 0 : -1}
                  ref={(node) => {
                    cellRefs.current.set(`${r}-${c}`, node);
                  }}
                  onFocus={() => setActive([r, c])}
                  className={[
                    "group relative flex min-h-[7.5rem] flex-col gap-1 border-r border-border p-1.5 text-left outline-none last:border-r-0",
                    "focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-inset",
                    cell.inMonth ? "bg-card" : "bg-muted/40",
                    cell.isToday ? "ring-1 ring-inset ring-primary" : "",
                  ].join(" ")}
                >
                  {/* day number + due flag */}
                  <div className="flex items-center justify-between">
                    <span
                      className={[
                        "inline-flex h-6 min-w-6 items-center justify-center rounded-full px-1.5 text-xs font-semibold tabular-nums",
                        cell.isToday
                          ? "bg-primary text-primary-foreground"
                          : cell.inMonth
                          ? cell.weekday === 0
                            ? "text-destructive"
                            : cell.weekday === 6
                            ? "text-info"
                            : "text-foreground"
                          : "text-muted-foreground",
                      ].join(" ")}
                    >
                      {cell.dayOfMonth}
                    </span>
                    {dues.length > 0 && (
                      <span
                        className="inline-flex items-center gap-0.5 rounded-sm bg-destructive-subtle px-1 text-[10px] font-semibold text-destructive-subtle-foreground"
                        title={`入稿締切 ${dues.length}件`}
                      >
                        <Icon icon={IconFlag} size="sm" aria-hidden />
                        締切{dues.length}
                      </span>
                    )}
                  </div>

                  {/* publish chips */}
                  <div className="flex flex-col gap-1">
                    {pubs.slice(0, MAX_CHIPS).map((a) => {
                      const st = STATUS_BY_ID[a.status];
                      const ch = CHANNEL_BY_ID[a.channel];
                      const overdue = isOverdue(a, todayIso);
                      return (
                        <button
                          key={a.id}
                          type="button"
                          onClick={(e) => {
                            e.stopPropagation();
                            onSelectArticle(a);
                          }}
                          className="flex w-full flex-col items-start gap-0.5 rounded-md border border-border bg-background px-1.5 py-1 text-left transition-colors hover:border-ring hover:bg-accent focus:outline-none focus-visible:ring-2 focus-visible:ring-ring"
                          aria-label={`記事「${a.title}」${ch.label}・${st.label}${
                            overdue ? "・締切超過" : ""
                          }`}
                        >
                          <span className="flex w-full items-center gap-1">
                            <span className="rounded-sm bg-muted px-1 text-[10px] font-bold text-muted-foreground">
                              {ch.code}
                            </span>
                            <span className="line-clamp-1 flex-1 text-[11px] font-medium leading-tight text-foreground">
                              {a.title}
                            </span>
                          </span>
                          <span className="flex items-center gap-1">
                            <Badge
                              variant={st.badge}
                              icon={
                                overdue ? (
                                  <IconClockExclamation />
                                ) : (
                                  <STATUS_BADGE_ICON />
                                )
                              }
                              className="h-4 px-1.5 text-[10px]"
                            >
                              {st.code}
                            </Badge>
                          </span>
                        </button>
                      );
                    })}
                    {overflow > 0 && (
                      <Button
                        variant="ghost"
                        size="sm"
                        className="h-6 justify-start px-1.5 text-[11px] text-muted-foreground"
                        onClick={(e) => {
                          e.stopPropagation();
                          onSelectDay(cell.iso);
                        }}
                      >
                        ＋他 {overflow} 件
                      </Button>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        ))}
      </div>
    </div>
  );
}

function cellAriaLabel(
  cell: DayCell,
  pubs: Article[],
  dues: Article[],
  todayIso: string
): string {
  const m = cell.date.getMonth() + 1;
  const d = cell.dayOfMonth;
  const wd = WEEKDAY_LABELS[cell.weekday];
  const parts = [`${m}月${d}日 ${wd}曜日`];
  if (cell.isToday) parts.push("今日");
  if (!cell.inMonth) parts.push("当月外");
  if (pubs.length) parts.push(`公開予定 ${pubs.length}件`);
  if (dues.length) parts.push(`入稿締切 ${dues.length}件`);
  const overdue = pubs.filter((a) => isOverdue(a, todayIso)).length;
  if (overdue) parts.push(`うち締切超過 ${overdue}件`);
  if (!pubs.length && !dues.length) parts.push("予定なし");
  return parts.join("、");
}
